INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('153ecdd8-f897-5df2-a954-8eeb041b909e', 'e5cf7677-1873-4e7a-ae65-3de4832151b1', 'I want to ___ a photo of this beautiful park.', '我想拍一張這座美麗公園的照片。', 'take', 'write', 'sing', 'read', 'take 在此表示「拍攝」。', 'take a photo → 拍照。'),
('5136ff23-eb37-5db7-8207-66bca1d1fd32', '23003a84-e1ef-406a-9685-a968690b269f', 'The team faced many challenges during the competition, but ___ was the lack of communication that caused the loss.', '團隊在比賽中面臨許多挑戰，但導致失敗的原因是缺乏溝通。', 'it', 'they', 'them', 'we', '代名詞，在此用於強調句或指代前述的整件事情。', 'it → 指代前面的整件事'),
('e05cd0d1-dc79-57e3-816e-0b84b41281c2', '05737cfc-81a1-42b1-9d5d-0c18e7a4370a', 'Is the computer ___? I need to finish my homework.', '電腦開著嗎？我需要完成作業。', 'on', 'up', 'in', 'by', '副詞，表示「開著的」或「運作中」的狀態。', '狀態的啟動 (activated state).'),
('67c659c4-a17f-575f-80e5-10f31a3cd51e', '689e8620-8af8-45d0-b3cc-53eb54374dfc', 'I like ___ blue pen.', '我喜歡這支藍色筆。', 'this', 'some', 'many', 'any', 'This 在此為形容詞，用來修飾後面的名詞。', 'This (這) → 放在名詞前面，表示「這一個」。');
